"use client";

import { type CodeBlockProps, CodeBlock as CodeBlockRoot } from "./code-block";
import { CodeBlockContent, type CodeBlockContentProps } from "./code-block-content";
import type { CodeBlockVariant } from "./code-block-context";
import { CodeBlockCopyButton, type CodeBlockCopyButtonProps } from "./code-block-copy-button";
import { CodeBlockHeader, type CodeBlockHeaderProps } from "./code-block-header";
import { CodeBlockLabel, type CodeBlockLabelProps } from "./code-block-label";
import {
  CodeBlockLine,
  type CodeBlockLineProps,
  type CodeBlockLineState,
  type CodeBlockToken,
} from "./code-block-line";
import { InlineCode } from "./inline-code";

const CodeBlock = Object.assign(CodeBlockRoot, {
  Content: CodeBlockContent,
  Header: CodeBlockHeader,
  Label: CodeBlockLabel,
  Line: CodeBlockLine,
  CopyButton: CodeBlockCopyButton,
  Inline: InlineCode,
});

export {
  CodeBlock,
  CodeBlockContent,
  CodeBlockHeader,
  CodeBlockLabel,
  CodeBlockLine,
  CodeBlockCopyButton,
  InlineCode,
  type CodeBlockProps,
  type CodeBlockContentProps,
  type CodeBlockHeaderProps,
  type CodeBlockLabelProps,
  type CodeBlockLineProps,
  type CodeBlockCopyButtonProps,
  type CodeBlockToken,
  type CodeBlockLineState,
  type CodeBlockVariant,
};

"use client";

import {
  Children,
  type ComponentProps,
  isValidElement,
  type ReactNode,
  useId,
  useMemo,
} from "react";
import {
  type CodeBlockChrome,
  CodeBlockProvider,
  type CodeBlockVariant,
} from "./code-block-context";
import { CodeBlockLabel } from "./code-block-label";

function containsLabelElement(node: ReactNode): boolean {
  for (const child of Children.toArray(node)) {
    if (!isValidElement(child)) continue;
    if (child.type === CodeBlockLabel) return true;
    const nested = (child.props as { children?: ReactNode }).children;
    if (nested && containsLabelElement(nested)) return true;
  }
  return false;
}

export interface CodeBlockProps extends Omit<ComponentProps<"figure">, "children"> {
  variant?: CodeBlockVariant;
  language?: string;
  label?: string;
  chrome?: CodeBlockChrome;
  children?: ComponentProps<"figure">["children"];
}

function resolveAriaName(
  props: { "aria-label"?: string; "aria-labelledby"?: string },
  children: ComponentProps<"figure">["children"],
  labelId: string,
  fallbackName: string,
): { "aria-label"?: string; "aria-labelledby"?: string } {
  if (props["aria-label"] !== undefined || props["aria-labelledby"] !== undefined) return {};
  if (containsLabelElement(children)) return { "aria-labelledby": labelId };
  return { "aria-label": fallbackName };
}

export function CodeBlock({
  variant,
  language,
  label,
  chrome,
  className,
  children,
  ref,
  ...props
}: CodeBlockProps) {
  const resolvedVariant: CodeBlockVariant = variant ?? "hairline";
  const resolvedChrome: CodeBlockChrome =
    chrome ?? (resolvedVariant === "terminal" ? "dots" : "none");
  const labelId = useId();

  const fallbackName = label ?? (language ? `${language} code` : "Code block");

  const hasLabel = containsLabelElement(children);

  const contextValue = useMemo(
    () => ({
      variant: resolvedVariant,
      chrome: resolvedChrome,
      labelId,
      hasLabel,
      language,
      fallbackName,
    }),
    [resolvedVariant, resolvedChrome, labelId, hasLabel, language, fallbackName],
  );

  const ariaProps = resolveAriaName(props, children, labelId, fallbackName);

  return (
    <CodeBlockProvider value={contextValue}>
      <figure
        ref={ref}
        data-slot="code-block"
        data-variant={resolvedVariant}
        data-chrome={resolvedChrome}
        data-language={language}
        className={className}
        {...ariaProps}
        {...props}
      >
        {resolvedChrome === "dots" ? (
          <span aria-hidden="true" data-slot="code-block-dots">
            <span />
            <span />
            <span />
          </span>
        ) : null}
        {children}
      </figure>
    </CodeBlockProvider>
  );
}

"use client";

import { createContext, useContext } from "react";

export type CodeBlockVariant = "hairline" | "bare" | "terminal";

export type CodeBlockChrome = "dots" | "none";

export interface CodeBlockContextValue {
  variant: CodeBlockVariant;
  chrome: CodeBlockChrome;
  labelId: string;
  hasLabel: boolean;
  language: string | undefined;
  fallbackName: string;
}

const CodeBlockContext = createContext<CodeBlockContextValue | null>(null);

export const CodeBlockProvider = CodeBlockContext.Provider;

export function useRequiredCodeBlockContext(consumerName: string): CodeBlockContextValue {
  const context = useContext(CodeBlockContext);
  if (!context) {
    throw new Error(`${consumerName} must be used inside <CodeBlock>`);
  }
  return context;
}

"use client";

import { Children, type ComponentProps } from "react";
import { ScrollArea } from "../scroll-area/scroll-area";
import { useRequiredCodeBlockContext } from "./code-block-context";
import { CodeBlockLine } from "./code-block-line";

export interface CodeBlockContentProps extends ComponentProps<"div"> {
  showLineNumbers?: boolean;
  lineCount?: number;
}

export function CodeBlockContent({
  showLineNumbers = true,
  lineCount: lineCountProp,
  className,
  children,
  ref,
  "aria-label": ariaLabel,
  "aria-labelledby": ariaLabelledBy,
  ...props
}: CodeBlockContentProps) {
  const context = useRequiredCodeBlockContext("CodeBlock.Content");
  const hasExplicitName = Boolean(ariaLabel || ariaLabelledBy);
  // Only reference labelId when a CodeBlock.Label is actually rendered,
  // otherwise the aria-labelledby would point at a non-existent element.
  const resolvedLabelledBy =
    ariaLabelledBy ?? (hasExplicitName || !context.hasLabel ? undefined : context.labelId);
  const resolvedLabel = hasExplicitName
    ? ariaLabel
    : context.hasLabel
      ? undefined
      : context.fallbackName;

  const isString = typeof children === "string";
  const lines = isString ? (children as string).split("\n") : null;
  const lineCount = lineCountProp ?? (lines ? lines.length : Children.count(children));
  const gutterWidth = Math.max(String(lineCount).length, 2);

  return (
    <ScrollArea
      orientation="both"
      tabIndex={0}
      ref={ref}
      aria-label={resolvedLabel}
      aria-labelledby={resolvedLabelledBy}
      className={className}
      {...props}
    >
      <pre
        data-slot="code-block-content"
        style={{ "--cb-line-number-w": `${gutterWidth}ch` } as React.CSSProperties}
      >
        {lines
          ? lines.map((line, i) => (
              // biome-ignore lint/suspicious/noArrayIndexKey: code lines render in fixed source order and are never reordered; the line index is the stable identity (line content can repeat).
              <CodeBlockLine key={i} number={showLineNumbers ? i + 1 : undefined} content={line} />
            ))
          : children}
      </pre>
    </ScrollArea>
  );
}

"use client";

import type { ComponentProps } from "react";
import { useRequiredCodeBlockContext } from "./code-block-context";

export type CodeBlockHeaderProps = ComponentProps<"div">;

export function CodeBlockHeader({ className, ref, ...props }: CodeBlockHeaderProps) {
  const context = useRequiredCodeBlockContext("CodeBlock.Header");
  if (context.variant === "bare") return null;
  return <div ref={ref} data-slot="code-block-header" className={className} {...props} />;
}

"use client";

import type { ComponentProps } from "react";
import { useRequiredCodeBlockContext } from "./code-block-context";

export type CodeBlockLabelProps = ComponentProps<"span">;

export function CodeBlockLabel({ id, className, children, ref, ...props }: CodeBlockLabelProps) {
  const context = useRequiredCodeBlockContext("CodeBlock.Label");
  const resolvedId = id ?? context.labelId;

  return (
    <span ref={ref} id={resolvedId} data-slot="code-block-label" className={className} {...props}>
      {children}
    </span>
  );
}

import type { ComponentProps, ReactNode } from "react";

export interface CodeBlockToken {
  text: string;
  color?: string;
  className?: string;
}

export type CodeBlockLineState = "highlight" | "added" | "removed";

export interface CodeBlockLineProps extends Omit<ComponentProps<"span">, "content" | "children"> {
  number?: number;
  content?: string | CodeBlockToken[];
  children?: ReactNode;
  state?: CodeBlockLineState;
}

const NON_BREAKING_SPACE = " ";

function signCharacter(state: CodeBlockLineState | undefined): string {
  if (state === "added") return "+";
  if (state === "removed") return "−";
  return NON_BREAKING_SPACE;
}

function renderContent(content: string | CodeBlockToken[] | undefined): ReactNode {
  if (content == null) return null;
  if (typeof content === "string") return content;
  return content.map((token, i) => (
    // biome-ignore lint/suspicious/noArrayIndexKey: syntax tokens render in fixed left-to-right order within a line and are never reordered; the token index is the stable identity.
    <span key={i} style={{ color: token.color }} className={token.className}>
      {token.text}
    </span>
  ));
}

export function CodeBlockLine({
  number,
  content,
  children,
  state,
  className,
  ref,
  ...props
}: CodeBlockLineProps) {
  const isDiffLine = state === "added" || state === "removed";
  return (
    <span
      ref={ref}
      data-slot="code-block-line"
      data-line-state={state}
      className={className}
      {...props}
    >
      {number != null ? (
        <span aria-hidden="true" data-slot="code-block-line-number">
          {number}
        </span>
      ) : null}
      <span aria-hidden="true" data-slot="code-block-line-sign">
        {signCharacter(state)}
      </span>
      {isDiffLine ? (
        <span className="sr-only">{state === "added" ? "Added: " : "Removed: "}</span>
      ) : null}
      <code>{children ?? renderContent(content)}</code>
    </span>
  );
}

"use client";

import { type ComponentProps, type ReactNode, useEffect, useRef, useState } from "react";

export interface CodeBlockCopyButtonProps
  extends Omit<ComponentProps<"button">, "children" | "onCopy"> {
  source: string;
  copyLabel?: string;
  copiedMessage?: string;
  children?: ((state: "idle" | "copied") => ReactNode) | ReactNode;
  onCopy?: (source: string) => void;
  onCopyError?: (error: unknown) => void;
}

const COPIED_TIMEOUT_MS = 2000;

function ClipboardIcon({ state }: { state: "idle" | "copied" }) {
  if (state === "copied") {
    return (
      <svg
        aria-hidden="true"
        viewBox="0 0 16 16"
        width="14"
        height="14"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="square"
        strokeLinejoin="miter"
      >
        <path d="M3 8.5l3 3 7-7" />
      </svg>
    );
  }
  return (
    <svg
      aria-hidden="true"
      viewBox="0 0 16 16"
      width="14"
      height="14"
      fill="none"
      stroke="currentColor"
      strokeWidth="1.5"
      strokeLinecap="square"
      strokeLinejoin="miter"
    >
      <rect x="5" y="2.5" width="6" height="2" />
      <rect x="3.5" y="4.5" width="9" height="9" />
    </svg>
  );
}

export function CodeBlockCopyButton({
  source,
  copyLabel = "Copy code to clipboard",
  copiedMessage = "Copied",
  className,
  children,
  onClick,
  onCopy,
  onCopyError,
  ref,
  ...props
}: CodeBlockCopyButtonProps) {
  const [state, setState] = useState<"idle" | "copied">("idle");
  const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Clear pending reset timer if the button unmounts before the 2s elapses.
  useEffect(() => {
    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
    };
  }, []);

  const handleClick = async (event: React.MouseEvent<HTMLButtonElement>) => {
    onClick?.(event);
    if (event.defaultPrevented) return;
    if (!navigator.clipboard) {
      onCopyError?.(new Error("Clipboard API unavailable"));
      return;
    }
    try {
      await navigator.clipboard.writeText(source);
      setState("copied");
      onCopy?.(source);
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      timeoutRef.current = setTimeout(() => setState("idle"), COPIED_TIMEOUT_MS);
    } catch (error) {
      onCopyError?.(error);
    }
  };

  const renderedChildren =
    typeof children === "function"
      ? children(state)
      : (children ?? <ClipboardIcon state={state} />);

  return (
    <>
      <button
        ref={ref}
        type="button"
        data-slot="code-block-copy-button"
        data-state={state}
        aria-label={copyLabel}
        className={className}
        onClick={handleClick}
        {...props}
      >
        {renderedChildren}
      </button>
      <span aria-live="polite" className="sr-only">
        {state === "copied" ? copiedMessage : ""}
      </span>
    </>
  );
}

import type { ComponentProps } from "react";
import { cn } from "@/lib/utils";

export function InlineCode({ className, ...props }: ComponentProps<"code">) {
  return (
    <code
      className={cn(
        "bg-secondary text-foreground px-1.5 py-0.5 text-xs font-mono rounded-sm",
        className,
      )}
      {...props}
    />
  );
}

/*
 * CodeBlock primitive styles. The component renders three variants
 * keyed via [data-slot="code-block"][data-variant="..."] on the root
 * <figure>. Shared typography lives on the root; per-variant chrome
 * lives in its own block. Token color classes (.code-*) and the
 * highlight.js (.hljs-*) compatibility map are kept here so consumers
 * get correct colors out of the box once shared/code-block.css is loaded.
 */
@layer components {
  [data-slot="code-block"] {
    --cb-bg: var(--background);
    --cb-fg: var(--foreground);
    --cb-border: var(--border);
    --cb-border-soft: color-mix(in oklab, var(--border) 60%, transparent);
    --cb-muted: var(--muted-foreground);
    --cb-header-h: 32px;

    position: relative;
    display: block;
    margin: 0;
    background: var(--cb-bg);
    color: var(--cb-fg);
    overflow: hidden;
    border-radius: 2px;
  }

  [data-slot="code-block-content"] {
    margin: 0;
    padding: 12px 0;
    font-family: var(--tui-font-mono, ui-monospace, SFMono-Regular, Menlo, monospace);
    font-size: 13px;
    line-height: 1.45;
    letter-spacing: 0;
    font-feature-settings:
      "calt" 0,
      "liga" 0,
      "zero" 1,
      "ss01" 1;
    font-variant-ligatures: none;
    font-variant-numeric: tabular-nums;
  }

  [data-slot="code-block-content"] > code {
    display: block;
    padding-inline: 12px;
  }

  [data-slot="code-block"] [data-slot="code-block-line"] {
    display: flex;
    align-items: baseline;
    padding-left: 12px;
    padding-right: 12px;
    /* Preserve row height for empty source lines (replaces U+200B fallback). */
    min-height: 1.45em;
  }

  [data-slot="code-block-line-number"] {
    flex: 0 0 auto;
    width: var(--cb-line-number-w, 2ch);
    min-width: var(--cb-line-number-w, 2ch);
    padding-right: 12px;
    text-align: right;
    user-select: none;
    color: color-mix(in oklab, var(--cb-muted) 50%, transparent);
  }

  [data-slot="code-block-line-sign"] {
    flex: 0 0 1ch;
    padding-right: 6px;
    text-align: center;
    user-select: none;
    color: color-mix(in oklab, var(--cb-muted) 70%, transparent);
  }

  [data-slot="code-block-line"] > code {
    white-space: pre;
    min-width: 0;
    flex: 1 1 auto;
  }

  /* Row state tints applied to the line, not <code>. */
  [data-slot="code-block-line"][data-line-state="added"] {
    background: color-mix(in oklab, var(--success, #2ea043) 12%, transparent);
  }

  [data-slot="code-block-line"][data-line-state="added"] [data-slot="code-block-line-sign"] {
    color: color-mix(in oklab, var(--success, #2ea043) 90%, var(--cb-fg));
  }

  [data-slot="code-block-line"][data-line-state="removed"] {
    background: color-mix(in oklab, var(--destructive, #f85149) 12%, transparent);
  }

  [data-slot="code-block-line"][data-line-state="removed"] [data-slot="code-block-line-sign"] {
    color: color-mix(in oklab, var(--destructive, #f85149) 90%, var(--cb-fg));
  }

  [data-slot="code-block-line"][data-line-state="highlight"] {
    background: color-mix(in oklab, var(--cb-fg) 8%, transparent);
  }

  /* Header chrome. */
  [data-slot="code-block-header"] {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: var(--cb-header-h);
    padding: 0 12px;
    border-bottom: 1px solid var(--cb-border-soft);
  }

  [data-slot="code-block-label"] {
    font-family: var(--tui-font-mono, ui-monospace, SFMono-Regular, Menlo, monospace);
    font-size: 12px;
    font-weight: 400;
    line-height: 1;
    color: color-mix(in oklab, var(--cb-fg) 80%, transparent);
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  /* Variant: hairline (default). */
  [data-slot="code-block"][data-variant="hairline"] {
    border: 1px solid var(--cb-border-soft);
  }

  /* Variant: bare. */
  [data-slot="code-block"][data-variant="bare"] {
    border: 0;
    border-left: 2px solid var(--cb-border);
    background: transparent;
    border-radius: 0;
    transition: border-color 120ms ease;
  }

  [data-slot="code-block"][data-variant="bare"]:hover {
    border-left-color: var(--ring, var(--cb-fg));
  }

  [data-slot="code-block"][data-variant="bare"] [data-slot="code-block-header"] {
    display: none;
  }

  /* Variant: terminal. */
  [data-slot="code-block"][data-variant="terminal"] {
    border: 1px solid var(--cb-border-soft);
  }

  [data-slot="code-block"][data-variant="terminal"] [data-slot="code-block-header"] {
    position: relative;
    justify-content: center;
  }

  /* Chrome="dots" anywhere: anchor dots to the header strip, balance the
     centered label with symmetric padding (12px outer + 3*9 dots + 2*6 gaps
     ≈ 51 → round to 52). */
  [data-slot="code-block"][data-chrome="dots"] [data-slot="code-block-header"] {
    position: relative;
    justify-content: center;
    padding-inline: 52px;
  }

  [data-slot="code-block-dots"] {
    /* Anchor to the header strip (cb-header-h tall), not the figure midpoint,
       so dots sit beside the centered title regardless of content length. */
    position: absolute;
    left: 12px;
    top: 0;
    height: var(--cb-header-h);
    display: inline-flex;
    align-items: center;
    gap: 6px;
    pointer-events: none;
  }

  [data-slot="code-block-dots"] span {
    width: 9px;
    height: 9px;
    border-radius: 50%;
    background: color-mix(in oklab, var(--cb-border) 70%, transparent);
  }

  /* Self-protecting: hide chrome dots if no header is rendered. */
  [data-slot="code-block"]:not(:has([data-slot="code-block-header"]))
    [data-slot="code-block-dots"] {
    display: none;
  }

  /* Copy button. */
  [data-slot="code-block-copy-button"] {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 24px;
    height: 24px;
    padding: 0;
    margin: 0;
    background: transparent;
    border: 0;
    border-radius: 2px;
    color: color-mix(in oklab, var(--cb-fg) 60%, transparent);
    cursor: pointer;
    transition:
      color 120ms ease,
      background-color 120ms ease;
  }

  [data-slot="code-block-copy-button"]:hover {
    color: var(--cb-fg);
    background: color-mix(in oklab, var(--cb-fg) 8%, transparent);
  }

  [data-slot="code-block-copy-button"][data-state="copied"] {
    color: var(--success, #2ea043);
  }

  [data-slot="code-block-copy-button"]:focus-visible {
    outline: 2px solid var(--ring, var(--cb-fg));
    outline-offset: 2px;
  }

  /* Focus ring on the scrollable region. */
  [data-slot="code-block-content"]:focus-visible {
    outline: 2px solid var(--ring, var(--cb-fg));
    outline-offset: 2px;
  }

  /* Token color classes, addressable from inline-tokenized content
     (CodeBlockToken { className }) and from the lowlight-emitted
     hljs-* classes via the compatibility map below. */
  [data-slot="code-block"] .code-comment,
  [data-slot="code-block"] .hljs-comment,
  [data-slot="code-block"] .hljs-quote {
    color: var(--code-comment);
    font-style: italic;
  }

  [data-slot="code-block"] .code-string,
  [data-slot="code-block"] .hljs-string,
  [data-slot="code-block"] .hljs-symbol,
  [data-slot="code-block"] .hljs-bullet,
  [data-slot="code-block"] .hljs-regexp {
    color: var(--code-string);
  }

  [data-slot="code-block"] .code-number,
  [data-slot="code-block"] .hljs-number,
  [data-slot="code-block"] .hljs-literal {
    color: var(--code-number);
  }

  [data-slot="code-block"] .code-keyword,
  [data-slot="code-block"] .hljs-keyword,
  [data-slot="code-block"] .hljs-selector-tag,
  [data-slot="code-block"] .hljs-meta-keyword {
    color: var(--code-keyword);
  }

  [data-slot="code-block"] .code-function,
  [data-slot="code-block"] .hljs-title,
  [data-slot="code-block"] .hljs-title.function_,
  [data-slot="code-block"] .hljs-section {
    color: var(--code-function);
  }

  [data-slot="code-block"] .code-tag,
  [data-slot="code-block"] .hljs-tag,
  [data-slot="code-block"] .hljs-name {
    color: var(--code-tag);
  }

  [data-slot="code-block"] .code-attr,
  [data-slot="code-block"] .hljs-attr,
  [data-slot="code-block"] .hljs-attribute {
    color: var(--code-attr);
  }

  [data-slot="code-block"] .code-parameter,
  [data-slot="code-block"] .hljs-params {
    color: var(--code-parameter);
  }

  [data-slot="code-block"] .code-operator,
  [data-slot="code-block"] .hljs-operator,
  [data-slot="code-block"] .hljs-punctuation {
    color: var(--code-operator);
  }

  [data-slot="code-block"] .code-variable,
  [data-slot="code-block"] .hljs-variable,
  [data-slot="code-block"] .hljs-template-variable {
    color: var(--code-variable);
  }

  [data-slot="code-block"] .code-type,
  [data-slot="code-block"] .hljs-type,
  [data-slot="code-block"] .hljs-built_in,
  [data-slot="code-block"] .hljs-class .hljs-title {
    color: var(--code-type);
  }
}

@media (prefers-reduced-motion: reduce) {
  [data-slot="code-block"][data-variant="bare"],
  [data-slot="code-block-copy-button"] {
    transition: none;
  }
}

@media (forced-colors: active) {
  [data-slot="code-block"][data-variant="hairline"],
  [data-slot="code-block"][data-variant="terminal"] {
    border-color: CanvasText;
  }

  [data-slot="code-block"][data-variant="bare"] {
    border-left-color: CanvasText;
  }

  [data-slot="code-block-content"]:focus-visible,
  [data-slot="code-block-copy-button"]:focus-visible {
    outline-color: Highlight;
  }
}
